from flask import Flask, request, jsonify
from kafka import KafkaProducer
import os

app = Flask(__name__)

BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092").split(",")

producer = KafkaProducer(
    bootstrap_servers=BOOTSTRAP_SERVERS,
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    key_serializer=lambda v: v if v is None or isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
)

@app.post("/publish")
def publish():
    topic = request.args.get("topic") or (request.json.get("topic") if request.is_json else None)
    if not topic:
        return jsonify({"error": "missing topic"}), 400

    payload = None
    key = None

    if request.is_json:
        body = request.get_json(silent=True) or {}
        payload = body.get("message", body.get("payload", body))
        key = body.get("key")
    else:
        payload = request.form.get("message") or request.data or ""
        key = request.form.get("key")

    future = producer.send(topic, value=payload, key=key)
    record = future.get(timeout=10)
    return jsonify(
        {
            "topic": record.topic,
            "partition": record.partition,
            "offset": record.offset,
            "timestamp": record.timestamp,
        }
    ), 200

@app.get("/health")
def health():
    return jsonify({"status": "ok"}), 200

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8080"))
    app.run(host=host, port=port)